import { ImageResponse } from 'next/og';
import { NextRequest } from 'next/server';

export const runtime = 'edge';

// Font + logo baked in at build time — zero runtime dependencies
const LOGO = 'data:image/png;base64,';
const FONT_B64 = '';

// atob() is a global in both Edge and browser runtimes (not Node.js Buffer)
function decodeB64(b64: string): ArrayBuffer {
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) arr[i] = bin.charCodeAt(i);
  return arr.buffer;
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
export async function GET(_req: NextRequest) {
  return new ImageResponse(
    (
      <div style={{
        width: 1200, height: 630,
        display: 'flex', flexDirection: 'column',
        alignItems: 'center', justifyContent: 'center',
        background: '#03000A', position: 'relative', overflow: 'hidden',
        fontFamily: 'Montserrat',
      }}>
        <div style={{
          position: 'absolute', top: -180, left: -120, width: 640, height: 640,
          borderRadius: '50%',
          background: 'radial-gradient(circle,rgba(153,69,255,0.22) 0%,transparent 65%)',
          display: 'flex',
        }} />
        <div style={{
          position: 'absolute', bottom: -140, right: -100, width: 560, height: 560,
          borderRadius: '50%',
          background: 'radial-gradient(circle,rgba(20,241,149,0.14) 0%,transparent 65%)',
          display: 'flex',
        }} />
        <div style={{
          position: 'absolute', top: 0, left: 0, right: 0, height: 5,
          background: 'linear-gradient(90deg,#9945FF,#14F195,#9945FF)', display: 'flex',
        }} />
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img src={LOGO} width={148} height={148} style={{ borderRadius: 28, marginBottom: 30 }} />
        <div style={{
          display: 'flex', fontSize: 100, fontWeight: 900, color: '#FFFFFF',
          letterSpacing: '-0.03em', lineHeight: 1, marginBottom: 20, fontFamily: 'Montserrat',
        }}>BlockBite</div>
        <div style={{
          display: 'flex', fontSize: 26, fontWeight: 700,
          color: 'rgba(200,196,220,0.60)', letterSpacing: '0.04em', fontFamily: 'Montserrat',
        }}>Token Distribution Protocol</div>
      </div>
    ),
    {
      width: 1200, height: 630,
      headers: { 'Cache-Control': 'public, max-age=86400', 'Content-Type': 'image/png' },
      fonts: [{ name: 'Montserrat', data: decodeB64(FONT_B64), style: 'normal', weight: 900 }],
    },
  );
}
